// ===================================================
// WF-ADMIN Step 1: Bearer 토큰 인증 + action 파싱
// 인증 실패시 _action을 '_unauthorized'로 설정하여
// Switch에서 403 응답으로 라우팅
// ===================================================

const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || {};

// Authorization 헤더에서 Bearer 토큰 추출
const authHeader = headers.authorization || headers.Authorization || '';
let token = '';
if (typeof authHeader === 'string' && authHeader.startsWith('Bearer ')) {
  token = authHeader.substring(7).trim();
}

// 환경변수의 ADMIN_API_TOKEN과 비교
const expectedToken = $env.ADMIN_API_TOKEN || '';
const isValid = token.length > 0 && expectedToken.length > 0 && token === expectedToken;

// 인증 실패시 _action을 _unauthorized로 설정
const action = isValid ? (body.action || '').trim() : '_unauthorized';

// params 추출
const params = { ...body };
delete params.action;

return [{
  json: {
    _valid: isValid ? 'YES' : 'NO',
    _action: action,
    _params: params,
    _body: body
  }
}];

// ===================================================
// case 0: getApplications - 파라미터 파싱
// pending 상태의 파트너 신청 목록 조회
// ===================================================

const params = $input.first().json._params || {};
const limit = Math.min(Math.max(parseInt(params.limit) || 50, 1), 200);
const offset = Math.max(parseInt(params.offset) || 0, 0);

return [{
  json: {
    limit,
    offset
  }
}];

// ===================================================
// getApplications 응답 포맷
// ===================================================

const response = $input.first().json;
const applications = response.list || [];
const pageInfo = response.pageInfo || {};

return [{
  json: {
    success: true,
    data: {
      applications: applications,
      total: pageInfo.totalRows || applications.length
    },
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// case 1: approveApplication - 파라미터 검증
// WF-08 (partner-approve) 내부 호출
// ===================================================

const params = $input.first().json._params || {};

const applicationId = (params.application_id || '').toString().trim();
const memberId = (params.member_id || '').toString().trim();
const reviewerNote = (params.reviewer_note || '').toString().trim();

if (!applicationId || !memberId) {
  return [{
    json: {
      _error: true,
      success: false,
      error: {
        code: 'MISSING_PARAMS',
        message: 'application_id, member_id 파라미터가 필요합니다.'
      },
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    _error: false,
    applicationId,
    memberId,
    reviewerNote
  }
}];

// ===================================================
// approveApplication 응답 포맷 (WF-08 응답 전달)
// WF-08이 4xx/5xx를 반환해도 관리자 UI가 JSON 에러를 읽을 수 있게 정규화
// ===================================================

const response = $input.first().json || {};
const statusCode = Number(response.statusCode || 200);
const body = response.body || {};

if (statusCode >= 200 && statusCode < 300 && body && body.success !== false) {
  return [{
    json: {
      success: true,
      data: body.data || body,
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    success: false,
    error: (body && body.error) || {
      code: 'WF08_ERROR',
      message: '파트너 승인 워크플로우 호출에 실패했습니다.'
    },
    data: body && body.data ? body.data : null,
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// case 2: rejectApplication - 파라미터 검증
// tbl_Applications 상태를 rejected로 변경
// ===================================================

const params = $input.first().json._params || {};

const rowId = (params.row_id || '').toString().trim();
const rejectReason = (params.reject_reason || '').toString().trim();

if (!rowId) {
  return [{
    json: {
      _error: true,
      success: false,
      error: {
        code: 'MISSING_PARAMS',
        message: 'row_id 파라미터가 필요합니다.'
      },
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    _error: false,
    rowId,
    rejectReason
  }
}];

// ===================================================
// case 3: getPendingClasses - 파라미터 파싱
// 상태별 클래스 목록 + 파트너 이름 조인
// ===================================================

const params = $input.first().json._params || {};
const limit = Math.min(Math.max(parseInt(params.limit, 10) || 50, 1), 200);
const offset = Math.max(parseInt(params.offset, 10) || 0, 0);

function normalizeStatus(raw) {
  const text = String(raw || '').replace(/\s+/g, ' ').trim();
  const upper = text.toUpperCase();
  if (!text) return 'PENDING_REVIEW';
  if (upper === 'ACTIVE' || text.toLowerCase() === 'active') return 'ACTIVE';
  if (upper === 'PAUSED' || text.toLowerCase() === 'paused') return 'PAUSED';
  if (upper === 'ARCHIVED') return 'ARCHIVED';
  if (upper === 'REJECTED' || text.toLowerCase() === 'closed') return 'REJECTED';
  if (upper === 'PENDING_REVIEW' || upper === 'INACTIVE' || text.toLowerCase() === 'pending') return 'PENDING_REVIEW';
  return upper;
}

return [{
  json: {
    limit,
    offset,
    status: normalizeStatus(params.status || 'PENDING_REVIEW')
  }
}];

// ===================================================
// getPendingClasses 응답 포맷
// 레거시/신규 상태값을 모두 읽고 정규화된 값으로 반환
// ===================================================

const classesResponse = $('NocoDB Get Pending Classes').first().json;
const partnersResponse = $('NocoDB Get Partners (Classes Join)').first().json;
const params = $('Parse getPendingClasses').first().json;

const classesList = classesResponse.list || [];
const partnersList = partnersResponse.list || [];

function normalizeStatus(raw) {
  const text = String(raw || '').replace(/\s+/g, ' ').trim();
  const upper = text.toUpperCase();
  if (!text) return 'DRAFT';
  if (upper === 'ACTIVE' || text.toLowerCase() === 'active') return 'ACTIVE';
  if (upper === 'PAUSED' || text.toLowerCase() === 'paused') return 'PAUSED';
  if (upper === 'ARCHIVED') return 'ARCHIVED';
  if (upper === 'REJECTED' || text.toLowerCase() === 'closed') return 'REJECTED';
  if (upper === 'PENDING_REVIEW' || upper === 'INACTIVE' || text.toLowerCase() === 'pending') return 'PENDING_REVIEW';
  return upper;
}

function normalizeLevel(raw) {
  const text = String(raw || '').replace(/\s+/g, ' ').trim();
  const upper = text.toUpperCase();
  const lower = text.toLowerCase();
  if (!text) return '';
  if (upper === 'BEGINNER' || lower === 'beginner' || lower === 'basic' || text.includes('입문') || text.includes('초급')) return 'BEGINNER';
  if (upper === 'INTERMEDIATE' || lower === 'intermediate' || text.includes('중급')) return 'INTERMEDIATE';
  if (upper === 'ADVANCED' || lower === 'advanced' || lower === 'expert' || text.includes('심화') || text.includes('고급')) return 'ADVANCED';
  if (upper === 'ALL_LEVELS' || text.includes('전체')) return 'ALL_LEVELS';
  return upper;
}

function normalizeRegion(rawRegion, rawLocation, rawType) {
  const fromRegion = String(rawRegion || '').replace(/\s+/g, ' ').trim();
  const text = fromRegion || String(rawLocation || '').replace(/\s+/g, ' ').trim();
  const type = String(rawType || '').replace(/\s+/g, ' ').trim();
  const upper = text.toUpperCase();
  const primary = text.split(' ')[0];
  const map = {
    '서울': 'SEOUL','경기': 'GYEONGGI','경기도': 'GYEONGGI','인천': 'INCHEON','부산': 'BUSAN','대구': 'DAEGU','대전': 'DAEJEON','광주': 'GWANGJU','울산': 'ULSAN','세종': 'SEJONG','강원': 'GANGWON','강원도': 'GANGWON','충북': 'CHUNGBUK','충청북도': 'CHUNGBUK','충남': 'CHUNGNAM','충청남도': 'CHUNGNAM','전북': 'JEONBUK','전라북도': 'JEONBUK','전남': 'JEONNAM','전라남도': 'JEONNAM','경북': 'GYEONGBUK','경상북도': 'GYEONGBUK','경남': 'GYEONGNAM','경상남도': 'GYEONGNAM','제주': 'JEJU','제주도': 'JEJU','온라인': 'ONLINE','기타': 'OTHER'
  };
  if (type.includes('온라인') || text.includes('온라인') || upper === 'ONLINE' || upper.includes('ONLINE')) return 'ONLINE';
  if (!text) return '';
  if (map[text]) return map[text];
  if (map[primary]) return map[primary];
  return map[upper] || upper;
}

const partnerMap = {};
for (const p of partnersList) {
  if (p.partner_code) {
    partnerMap[p.partner_code] = p.partner_name || '';
  }
}

let classes = classesList.map((c) => {
  let partnerCode = '';
  if (Array.isArray(c.partner_code) && c.partner_code.length > 0) {
    partnerCode = c.partner_code[0].partner_code || c.partner_code[0].Title || '';
  } else if (typeof c.partner_code === 'string') {
    partnerCode = c.partner_code;
  }

  return {
    Id: c.Id || c.id,
    class_id: c.class_id || '',
    class_name: c.class_name || '',
    category: c.category || '',
    level: normalizeLevel(c.level || ''),
    price: Number(c.price) || 0,
    type: c.type || '',
    location: c.location || '',
    region: normalizeRegion(c.region || '', c.location || '', c.type || ''),
    partner_code: partnerCode,
    partner_name: partnerMap[partnerCode] || '',
    status: normalizeStatus(c.status || ''),
    created_date: c.created_date || ''
  };
});

classes = classes.filter((c) => c.status === params.status);
const total = classes.length;
classes = classes.slice(params.offset, params.offset + params.limit);

return [{
  json: {
    success: true,
    data: {
      classes,
      total
    },
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// case 4: approveClass - 파라미터 검증
// tbl_Classes 상태를 active로 변경 (NocoDB 웹훅이 WF-17 트리거)
// ===================================================

const params = $input.first().json._params || {};

const rowId = (params.row_id || '').toString().trim();

if (!rowId) {
  return [{
    json: {
      _error: true,
      success: false,
      error: {
        code: 'MISSING_PARAMS',
        message: 'row_id 파라미터가 필요합니다.'
      },
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    _error: false,
    rowId
  }
}];

// ===================================================
// case 5: rejectClass - 파라미터 검증
// tbl_Classes 상태를 closed로 변경
// ===================================================

const params = $input.first().json._params || {};

const rowId = (params.row_id || '').toString().trim();
const rejectReason = (params.reject_reason || '').toString().trim();

if (!rowId) {
  return [{
    json: {
      _error: true,
      success: false,
      error: {
        code: 'MISSING_PARAMS',
        message: 'row_id 파라미터가 필요합니다.'
      },
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    _error: false,
    rowId,
    rejectReason
  }
}];

// ===================================================
// case 6: getSettlements - 파라미터 파싱
// 상태값 기준 조회 후 월 필터는 응답 포맷 단계에서 처리
// ===================================================

const params = $input.first().json._params || {};
const limit = Math.min(Math.max(parseInt(params.limit) || 50, 1), 200);
const offset = Math.max(parseInt(params.offset) || 0, 0);
const month = (params.month || '').toString().trim();
const statusRaw = (params.status || 'PENDING_SETTLEMENT').toString().trim().toUpperCase();
const status = statusRaw === 'COMPLETED' ? 'COMPLETED' : 'PENDING_SETTLEMENT';
const where = '(status,eq,' + status + ')';

return [{
  json: {
    where,
    limit,
    offset,
    status,
    month
  }
}];

// ===================================================
// getSettlements 응답 포맷 + 집계 계산
// commission_rate 0.1 / 10 혼재값을 percent 기준으로 정규화
// ===================================================

const response = $input.first().json;
const params = $('Parse getSettlements').first().json;
const month = /^\d{4}-\d{2}$/.test(String(params.month || '').trim()) ? String(params.month || '').trim() : '';
let settlements = response.list || [];

if (month) {
  settlements = settlements.filter((item) => String(item.class_date || '').indexOf(month) === 0);
}

function normalizePercent(value) {
  const num = Number(value) || 0;
  if (!num) return 0;
  return num > 0 && num < 1 ? Math.round(num * 100) : num;
}

let totalOrderAmount = 0;
let totalCommission = 0;
let totalPartnerAmount = 0;

const formattedSettlements = settlements.map(s => {
  const orderAmount = Number(s.order_amount) || 0;
  const commissionAmount = Number(s.commission_amount) || 0;
  const reserveAmount = Number(s.reserve_amount) || (orderAmount - commissionAmount);
  const partnerAmount = Number(s.partner_amount) || reserveAmount;
  const commissionRate = normalizePercent(s.commission_rate);

  totalOrderAmount += orderAmount;
  totalCommission += commissionAmount;
  totalPartnerAmount += partnerAmount;

  return {
    Id: s.Id || s.id,
    settlement_id: s.settlement_id || '',
    order_id: s.order_id || '',
    partner_code: s.partner_code || '',
    partner_name: s.partner_name || s.partner || s.partner_code || '',
    class_id: s.class_id || '',
    class_name: s.class_name || s.class_title || s.class_id || '',
    class_date: s.class_date || '',
    order_amount: orderAmount,
    commission_rate: commissionRate,
    commission_amount: commissionAmount,
    reserve_amount: reserveAmount,
    partner_amount: partnerAmount,
    settlement_month: s.settlement_month || '',
    completed_date: s.completed_date || s.paid_at || '',
    status: s.status || '',
    CreatedAt: s.CreatedAt || ''
  };
});

return [{
  json: {
    success: true,
    data: {
      settlements: formattedSettlements,
      total: formattedSettlements.length,
      summary: {
        total_order_amount: totalOrderAmount,
        total_commission: totalCommission,
        total_partner_amount: totalPartnerAmount
      }
    },
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// case 7: completeSettlement - 파라미터 검증
// 여러 정산 건을 일괄 COMPLETED로 변경
// ===================================================

const params = $input.first().json._params || {};

// settlement_ids: 배열 또는 쉼표 구분 문자열
let settlementIds = [];
if (Array.isArray(params.settlement_ids)) {
  settlementIds = params.settlement_ids.map(id => String(id).trim()).filter(id => id.length > 0);
} else if (typeof params.settlement_ids === 'string') {
  settlementIds = params.settlement_ids.split(',').map(id => id.trim()).filter(id => id.length > 0);
}

if (settlementIds.length === 0) {
  return [{
    json: {
      _error: true,
      success: false,
      error: {
        code: 'MISSING_PARAMS',
        message: 'settlement_ids 파라미터가 필요합니다. (배열 또는 쉼표 구분 문자열)'
      },
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    _error: false,
    settlementIds
  }
}];

// ===================================================
// completeSettlement: settlement_id -> NocoDB row Id 매핑
// settlement_ids로 요청된 건들의 NocoDB row Id를 찾아서
// 일괄 업데이트용 데이터 구성
// ===================================================

const response = $input.first().json;
const allSettlements = response.list || [];
const requestedIds = $('Parse completeSettlement').first().json.settlementIds;

// settlement_id -> NocoDB row 매핑
const settlementMap = {};
for (const s of allSettlements) {
  const sid = s.settlement_id || '';
  if (sid) {
    settlementMap[sid] = {
      rowId: s.Id || s.id,
      orderAmount: Number(s.order_amount) || 0,
      commissionAmount: Number(s.commission_amount) || 0
    };
  }
}

// 요청된 ID 중 유효한 것들만 필터
const validItems = [];
const notFoundIds = [];
for (const sid of requestedIds) {
  if (settlementMap[sid]) {
    validItems.push({
      settlementId: sid,
      rowId: settlementMap[sid].rowId,
      orderAmount: settlementMap[sid].orderAmount,
      commissionAmount: settlementMap[sid].commissionAmount
    });
  } else {
    notFoundIds.push(sid);
  }
}

if (validItems.length === 0) {
  return [{
    json: {
      _hasItems: false,
      _response: {
        success: false,
        error: {
          code: 'NOT_FOUND',
          message: '유효한 PENDING 상태의 정산 건을 찾을 수 없습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// 각 항목을 SplitInBatches로 보내기 위해 배열로 리턴
const paidAt = new Date().toISOString();
let totalPaid = 0;
for (const item of validItems) {
  totalPaid += (item.orderAmount - item.commissionAmount);
}

return [{
  json: {
    _hasItems: true,
    _validItems: validItems,
    _paidAt: paidAt,
    _completedCount: validItems.length,
    _totalPaid: totalPaid,
    _notFoundIds: notFoundIds
  }
}];

// ===================================================
// completeSettlement: 각 정산 건을 개별 아이템으로 분할
// SplitInBatches 대신 Code에서 배열로 리턴
// ===================================================

const data = $input.first().json;
const items = data._validItems;
const paidAt = data._paidAt;

return items.map(item => ({
  json: {
    rowId: item.rowId,
    settlementId: item.settlementId,
    paidAt: paidAt,
    _completedCount: data._completedCount,
    _totalPaid: data._totalPaid,
    _notFoundIds: data._notFoundIds
  }
}));

// ===================================================
// completeSettlement: 최종 응답 구성
// 모든 PATCH 완료 후 집계 결과 리턴
// ===================================================

// 첫 번째 아이템에서 집계 정보 가져옴
const firstItem = $('Split Settlement Items').first().json;

return [{
  json: {
    success: true,
    data: {
      completed_count: firstItem._completedCount,
      total_paid: firstItem._totalPaid,
      not_found_ids: firstItem._notFoundIds
    },
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// Fallback: 알 수 없는 action 에러 응답
// ===================================================

const action = $input.first().json._action || '';

return [{
  json: {
    success: false,
    error: {
      code: 'INVALID_ACTION',
      message: '알 수 없는 요청입니다: ' + action
    },
    timestamp: new Date().toISOString()
  }
}];

// getAffilStats: 월간 집계 데이터 응답
const response = $input.first().json;
const list = response.list || [];

const stats = list.map(s => ({
  affiliation_code: s.affiliation_code || '',
  year: Number(s.year) || 0,
  month: Number(s.month) || 0,
  total_amount: Number(s.total_amount) || 0,
  member_count: Number(s.member_count) || 0,
  cumulative_amount: Number(s.cumulative_amount) || 0,
  incentive_level: Number(s.incentive_level) || 0,
  incentive_amount: Number(s.incentive_amount) || 0,
  incentive_paid: s.incentive_paid ? true : false
}));

return [{ json: { success: true, data: stats, total: stats.length, timestamp: new Date().toISOString() } }];
